/**
 * Unit test for ConfigCascade three-layer resolution of Role.model and
 * Role.thinkingLevel: project > server > builtin.
 */
import { afterAll, beforeAll, describe, it, vi } from "vitest";
import assert from "node:assert/strict";
import fs from "node:fs";
import path from "node:path";
import { createFsFromVolume, Volume } from "memfs";

import { ConfigCascade, normalizeConfigProjectId } from "../../src/server/agent/config-cascade.js";
import type { BuiltinConfigProvider } from "../../src/server/agent/builtin-config.js";
import type { Role } from "../../src/server/agent/role-store.js";
import { HEADQUARTERS_PROJECT_ID } from "../../src/server/agent/project-registry.js";

const memoryFs = createFsFromVolume(new Volume()) as unknown as typeof fs;
const fsSpies: Array<{ mockRestore(): void }> = [];
const emptyPackRoot = path.resolve("/memfs/config-cascade/empty");

beforeAll(() => {
	for (const name of [
		"existsSync", "lstatSync", "readFileSync", "readdirSync", "realpathSync", "statSync",
	] as const) {
		fsSpies.push(vi.spyOn(fs, name).mockImplementation(memoryFs[name].bind(memoryFs) as never));
	}
});

afterAll(() => fsSpies.forEach(spy => spy.mockRestore()));

function role(name: string, fields: Partial<Role> = {}): Role {
	return {
		name,
		label: name[0].toUpperCase() + name.slice(1),
		promptTemplate: "p",
		accessory: "none",
		createdAt: 0,
		updatedAt: 0,
		...fields,
	};
}

function builtinProvider(roles: readonly Role[] = []): BuiltinConfigProvider {
	return {
		getRoles: () => [...roles],
		getTools: () => [],
		getToolGroupPolicies: () => ({}),
	} as unknown as BuiltinConfigProvider;
}

function cascade(
	builtins: BuiltinConfigProvider,
	serverStores: any,
	projectContextManager: any,
): ConfigCascade {
	return new ConfigCascade(
		builtins,
		serverStores,
		projectContextManager,
		undefined,
		undefined,
		emptyPackRoot,
		emptyPackRoot,
	);
}

describe("ConfigCascade — Role.model and Role.thinkingLevel three-layer resolution", () => {
	it("project overrides server overrides builtin for both fields", () => {
		const builtinRole = role("coder", {
			model: "anthropic/claude-haiku",
			thinkingLevel: "low",
		});
		const serverRole = role("coder", {
			model: "anthropic/claude-sonnet",
			thinkingLevel: "medium",
		});
		const projectRole = role("coder", {
			model: "anthropic/claude-opus-4",
			thinkingLevel: "high",
		});
		const builtins = builtinProvider([builtinRole]);

		const serverStores = {
			getRoles: () => [serverRole],
			getPersonalities: () => [],
			getWorkflows: () => [],
			getTools: () => [],
			getToolGroupPolicies: () => ({}),
		};

		// Mock ProjectContextManager — only needs getOrCreate(projectId) to return a ctx with roleStore.
		const fakePcm = {
			getOrCreate: (id: string) => id === "proj1" ? { roleStore: { getAllLocal: () => [projectRole] } } : undefined,
		} as any;

		const configCascade = cascade(builtins, serverStores, fakePcm);

		// No project: server wins over builtin
		const sysRoles = configCascade.resolveRoles();
		const sysCoder = sysRoles.find(r => r.item.name === "coder");
		assert.ok(sysCoder);
		assert.equal(sysCoder!.origin, "server");
		assert.equal(sysCoder!.item.model, "anthropic/claude-sonnet");
		assert.equal(sysCoder!.item.thinkingLevel, "medium");

		// With project: project wins over server
		const projRoles = configCascade.resolveRoles("proj1");
		const projCoder = projRoles.find(r => r.item.name === "coder");
		assert.ok(projCoder);
		assert.equal(projCoder!.origin, "project");
		assert.equal(projCoder!.item.model, "anthropic/claude-opus-4");
		assert.equal(projCoder!.item.thinkingLevel, "high");
	});

	it("falls through to builtin when neither server nor project define the role", () => {
		const builtins = builtinProvider([role("tester", {
			model: "anthropic/claude-haiku",
			thinkingLevel: "off",
		})]);

		const serverStores = {
			getRoles: () => [],
			getPersonalities: () => [],
			getWorkflows: () => [],
			getTools: () => [],
			getToolGroupPolicies: () => ({}),
		};
		const fakePcm = { getOrCreate: () => undefined } as any;

		const configCascade = cascade(builtins, serverStores, fakePcm);
		const roles = configCascade.resolveRoles();
		const tester = roles.find(r => r.item.name === "tester");
		assert.ok(tester);
		assert.equal(tester!.origin, "builtin");
		assert.equal(tester!.item.model, "anthropic/claude-haiku");
		assert.equal(tester!.item.thinkingLevel, "off");
	});
});

describe("ConfigCascade — Headquarters server-scope alias", () => {
	it("normalizes Headquarters to server scope for non-workflow config only", () => {
		assert.equal(normalizeConfigProjectId(HEADQUARTERS_PROJECT_ID), undefined);
		assert.equal(normalizeConfigProjectId("proj1"), "proj1");

		const builtins = builtinProvider();
		const serverRole = role("coder", {
			label: "Coder",
			promptTemplate: "server prompt",
			model: "server/model",
			thinkingLevel: "medium",
		});
		const projectRole = {
			...serverRole,
			promptTemplate: "project prompt",
			model: "project/model",
			thinkingLevel: "high",
		};
		const serverTool = { name: "shared_tool", description: "server" };
		const projectTool = { name: "shared_tool", description: "project" };
		const serverPolicy = { default: "allow" };
		const projectPolicy = { default: "deny" };
		const hqWorkflow = { id: "hq-flow", name: "HQ Flow", gates: [] };
		const calls: string[] = [];
		const fakePcm = {
			getOrCreate: (id: string) => {
				calls.push(id);
				if (id !== HEADQUARTERS_PROJECT_ID) return undefined;
				return {
					roleStore: {
						getAllLocal: () => [projectRole],
						getLocal: (name: string) => name === "coder" ? projectRole : undefined,
					},
					toolManager: { getLocalTools: () => [projectTool] },
					toolGroupPolicyStore: { getAll: () => ({ Shell: projectPolicy }) },
					workflowStore: { getAllLocal: () => [hqWorkflow] },
				};
			},
		} as any;
		const configCascade = cascade(builtins, {
			getRoles: () => [serverRole],
			getTools: () => [serverTool as any],
			getToolGroupPolicies: () => ({ Shell: serverPolicy as any }),
		}, fakePcm);

		const roles = configCascade.resolveRoles(HEADQUARTERS_PROJECT_ID);
		assert.equal(roles.find(r => r.item.name === "coder")?.origin, "server");
		assert.equal(roles.find(r => r.item.name === "coder")?.item.promptTemplate, "server prompt");
		assert.equal(configCascade.resolveRoleModel("coder", HEADQUARTERS_PROJECT_ID), "server/model");
		assert.equal(configCascade.resolveRoleThinkingLevel("coder", HEADQUARTERS_PROJECT_ID), "medium");
		assert.equal(configCascade.resolveRolePromptTemplate("coder", HEADQUARTERS_PROJECT_ID), "server prompt");
		assert.equal(configCascade.resolveTools(HEADQUARTERS_PROJECT_ID).find(t => t.item.name === "shared_tool")?.origin, "server");
		assert.equal(configCascade.resolveToolGroupPolicies(HEADQUARTERS_PROJECT_ID).Shell.origin, "server");
		assert.deepEqual(calls, [], "non-workflow Headquarters config must not load the project context");

		const workflows = configCascade.resolveWorkflows(HEADQUARTERS_PROJECT_ID);
		assert.deepEqual(workflows.map(w => [w.item.id, w.origin]), [["hq-flow", "project"]]);
		assert.deepEqual(calls, [HEADQUARTERS_PROJECT_ID], "workflow resolution remains project-scoped for Headquarters");
	});

	it("normalizes Headquarters before market-pack and activation lookups", () => {
		const builtins = builtinProvider();
		const configCascade = cascade(builtins, {
			getRoles: () => [],
			getTools: () => [],
			getToolGroupPolicies: () => ({}),
		}, { getOrCreate: () => undefined } as any);
		const marketCalls: Array<[string, string | undefined]> = [];
		const activationCalls: Array<[string, string | undefined, string]> = [];
		configCascade.setMarketPackProvider({
			marketEntries(scope, projectId) {
				marketCalls.push([scope, projectId]);
				if (scope !== "server") return [];
				return [{
					id: "market:server:sample",
					kind: "market",
					scope: "server",
					path: path.join(emptyPackRoot, "sample"),
					readOnly: true,
					layout: "defaults-tree",
					manifest: {
						name: "sample",
						description: "sample",
						version: "1.0.0",
						contents: { roles: [], tools: ["market_tool"], skills: [], entrypoints: [] },
					},
					preloaded: { tools: [{ name: "market_tool", item: { name: "market_tool", description: "market" } }] },
				} as any];
			},
		});
		configCascade.setPackActivationProvider({
			disabled(scope, projectId, packName) {
				activationCalls.push([scope, projectId, packName]);
				return {};
			},
		});

		assert.equal(configCascade.resolveTools(HEADQUARTERS_PROJECT_ID).find(t => t.item.name === "market_tool")?.origin, "server");
		assert.deepEqual(marketCalls, [["server", undefined], ["global-user", undefined]]);
		assert.deepEqual(activationCalls, [["server", undefined, "sample"]]);
	});
});
